def trigger_snowflake_probe(
    current_user: Annotated[User, Depends(get_current_user)],
    db: Annotated[Session, Depends(get_db)],
) -> ProbeRunResponse:
    settings = get_settings()
    _, suite, _ = ensure_probe_fixtures(db, user=current_user, settings=settings)

    run = Run(suite_id=suite.id, status="queued", triggered_by=f"probe:{current_user.id}")
    db.add(run)
    db.commit()
    db.refresh(run)

    try:
        run_dispatch.dispatch_run(run.id)
    except Exception as exc:  # broker unreachable — don't leave the run stuck queued
        run.status = "failed"
        db.commit()
        raise HTTPException(
            status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
            detail="failed to dispatch run",
        ) from exc
    return ProbeRunResponse(run_id=run.id, status=run.status)


